signer.rust_types:
pub struct OptionUnitQty {
    pub tag: u64,
    pub unit: u64,
    pub value: u64,
}

pub struct UnitQty { pub unit: u64, pub qty: i64 }
pub struct AssetPosition { pub coin: u64, pub size: i64, pub entry_px: u64 }

pub struct AccountState {
    pub equity: Option<UnitQty>,
    pub isolated_equity: Option<UnitQty>,
    pub positions: std::collections::BTreeMap<u64, AssetPosition>,
}

pub struct MarginResult {
    pub total_equity: Option<UnitQty>,
    pub margin_req: Option<UnitQty>,
    pub abs_notional: Option<UnitQty>,
    pub raw_equity: Option<UnitQty>,
}
